package org.apache.commons.csv;
import java.io.Closeable;
import java.io.File;
import java.io.FileInputStream;
import java.io.FileReader;
import java.io.InputStreamReader;
import java.io.Reader;
import java.net.URL;
import java.nio.charset.Charset;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collection;
import java.util.Iterator;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.NoSuchElementException;
import static org.apache.commons.csv.Token.Type.*;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringReader;

import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserTest {

    @Test
    void parse_WithValidStringAndFormat_ReturnsCSVParser() throws IOException {
        String input = "header1,header2\nvalue1,value2";
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            // No exception on notNull checks
            mockedAssertions.when(() -> Assertions.notNull(input, "string")).thenCallRealMethod();
            mockedAssertions.when(() -> Assertions.notNull(format, "format")).thenCallRealMethod();

            CSVParser parser = CSVParser.parse(input, format);

            assertNotNull(parser);
            // Validate that the parser was constructed with a StringReader wrapping the input string
            assertFalse(parser.isClosed());
            assertEquals(format, parser.format);
        }
    }

    @Test
    void parse_WithNullString_ThrowsNullPointerException() {
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            mockedAssertions.when(() -> Assertions.notNull(null, "string"))
                .thenThrow(new NullPointerException("string"));

            NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
                CSVParser.parse(null, format);
            });
            assertEquals("string", thrown.getMessage());
        }
    }

    @Test
    void parse_WithNullFormat_ThrowsNullPointerException() {
        String input = "a,b,c";

        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            mockedAssertions.when(() -> Assertions.notNull(input, "string")).thenCallRealMethod();
            mockedAssertions.when(() -> Assertions.notNull(null, "format"))
                .thenThrow(new NullPointerException("format"));

            NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
                CSVParser.parse(input, null);
            });
            assertEquals("format", thrown.getMessage());
        }
    }
}
